        "        rt_cat, val_col='response_time_min',\n",
        "        group_col='incident_category', p_adjust='bonferroni'\n",
        "    )\n",
        "    print(dunn2.round(4))\n",
        "else:\n",
        "    rt_cat = disp_rt[disp_rt['incident_category'].isin(cat_labels)].dropna(subset=['response_time_min'])\n",
        "    dunn_df2 = dunn_posthoc_manual(rt_cat, 'incident_category', 'response_time_min')\n",
        "    print(dunn_df2.to_string(index=False))"
